  1→import { getPartExtents } from './viewProjection';
  2→
  3→function getAnchorPosition(part, anchor) {
  4→  const ext = getPartExtents(part);
  5→  const pos = part.position;
  6→
  7→  switch (anchor) {
  8→    case 'top': return pos.z + ext.height;
  9→    case 'bottom': return pos.z;
 10→    case 'left': return pos.x;
 11→    case 'right': return pos.x + ext.width;
 12→    case 'front': return pos.y;
 13→    case 'back': return pos.y + ext.depth;
 14→    case 'center': return null; // handled per-type
 15→    default: return 0;
 16→  }
 17→}
 18→
 19→function getAnchorAxis(anchor) {
 20→  switch (anchor) {
 21→    case 'top':
 22→    case 'bottom':
 23→      return 'z';
 24→    case 'left':
 25→    case 'right':
 26→      return 'x';
 27→    case 'front':
 28→    case 'back':
 29→      return 'y';
 30→    case 'center':
 31→      return null;
 32→    default:
 33→      return null;
 34→  }
 35→}
 36→
 37→function getAnchorExtentSize(part, anchor) {
 38→  const ext = getPartExtents(part);
 39→  switch (anchor) {
 40→    case 'top':
 41→    case 'bottom':
 42→      return ext.height;
 43→    case 'left':
 44→    case 'right':
 45→      return ext.width;
 46→    case 'front':
 47→    case 'back':
 48→      return ext.depth;
 49→    default:
 50→      return 0;
 51→  }
 52→}
 53→
 54→function getPartSizeOnAxis(part, axis) {
 55→  const ext = getPartExtents(part);
 56→  switch (axis) {
 57→    case 'x': return ext.width;
 58→    case 'y': return ext.depth;
 59→    case 'z': return ext.height;
 60→    default: return 0;
 61→  }
 62→}
 63→
 64→function resolveEqualSpacing(constraint, partsById, positions) {
 65→  const parts = constraint.partIds
 66→    .map((id) => partsById.get(id))
 67→    .filter(Boolean);
 68→
 69→  if (parts.length < 2) return;
 70→
 71→  const axis = constraint.axis || 'z';
 72→  const refPart = constraint.referencePartId ? partsById.get(constraint.referencePartId) : null;
 73→
 74→  // Get effective positions (use already-resolved if available)
 75→  const getPos = (part) => ({
 76→    ...part.position,
 77→    ...(positions.get(part.id) || {}),
 78→  });
 79→
 80→  let rangeStart, rangeEnd;
 81→
 82→  if (refPart) {
 83→    const refPos = getPos(refPart);
 84→    const refExt = getPartExtents({ ...refPart, position: refPos });
 85→    const startAnchor = constraint.startAnchor || 'bottom';
 86→    const endAnchor = constraint.endAnchor || 'top';
 87→
 88→    const startPart = { ...refPart, position: refPos };
 89→    rangeStart = getAnchorPosition(startPart, startAnchor) ?? refPos[axis];
 90→    rangeEnd = getAnchorPosition(startPart, endAnchor) ?? (refPos[axis] + getPartSizeOnAxis(startPart, axis));
 91→  } else {
 92→    // Compute range from min/max of the parts themselves
 93→    let min = Infinity, max = -Infinity;
 94→    for (const part of parts) {
 95→      const pos = getPos(part);
 96→      const size = getPartSizeOnAxis({ ...part, position: pos }, axis);
 97→      min = Math.min(min, pos[axis]);
 98→      max = Math.max(max, pos[axis] + size);
 99→    }
100→    rangeStart = min;
101→    rangeEnd = max;
102→  }
103→
104→  const rangeSize = rangeEnd - rangeStart;
105→
106→  // Sort parts by current position on axis
107→  const sorted = [...parts].sort((a, b) => {
108→    const posA = getPos(a);
109→    const posB = getPos(b);
110→    return posA[axis] - posB[axis];
111→  });
112→
113→  const totalPartSize = sorted.reduce((sum, part) => {
114→    return sum + getPartSizeOnAxis({ ...part, position: getPos(part) }, axis);
115→  }, 0);
116→
117→  const gap = (rangeSize - totalPartSize) / (sorted.length + 1);
118→
119→  let cursor = rangeStart;
120→  for (const part of sorted) {
121→    cursor += gap;
122→    const pos = getPos(part);
123→    const newPos = { ...pos, [axis]: cursor };
124→    cursor += getPartSizeOnAxis({ ...part, position: pos }, axis);
125→    positions.set(part.id, newPos);
126→  }
127→}
128→
129→export function resolveConstraints(constraints, parts) {
130→  const positions = new Map();
131→  const partsById = new Map(parts.map((p) => [p.id, p]));
132→
133→  for (const constraint of constraints) {
134→    if (constraint.type === 'equal_spacing') {
135→      resolveEqualSpacing(constraint, partsById, positions);
136→      continue;
137→    }
138→
139→    const source = partsById.get(constraint.sourcePartId);
140→    const target = partsById.get(constraint.targetPartId);
141→    if (!source || !target) continue;
142→
143→    // Use already-resolved position if available
144→    const sourcePos = { ...source.position, ...(positions.get(source.id) || {}) };
145→    const targetPos = { ...target.position, ...(positions.get(target.id) || {}) };
146→
147→    const workingSource = { ...source, position: sourcePos };
148→    const workingTarget = { ...target, position: targetPos };
149→
150→    const newPos = { ...sourcePos };
151→
152→    switch (constraint.type) {
153→      case 'attach_face': {
154→        const axis = getAnchorAxis(constraint.targetAnchor);
155→        if (!axis) break;
156→        const targetAnchorVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
157→        const sourceExtent = getAnchorExtentSize(workingSource, constraint.sourceAnchor);
158→
159→        // Position source so its sourceAnchor face touches target's targetAnchor face
160→        if (constraint.sourceAnchor === 'bottom' || constraint.sourceAnchor === 'left' || constraint.sourceAnchor === 'front') {
161→          newPos[axis] = targetAnchorVal + constraint.offset;
162→        } else {
163→          newPos[axis] = targetAnchorVal - sourceExtent + constraint.offset;
164→        }
165→        break;
166→      }
167→
168→      case 'flush_surface': {
169→        const axis = getAnchorAxis(constraint.targetAnchor);
170→        if (!axis) break;
171→        const targetAnchorVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
172→        const sourceExtent = getAnchorExtentSize(workingSource, constraint.sourceAnchor);
173→
174→        if (constraint.sourceAnchor === 'bottom' || constraint.sourceAnchor === 'left' || constraint.sourceAnchor === 'front') {
175→          newPos[axis] = targetAnchorVal;
176→        } else {
177→          newPos[axis] = targetAnchorVal - sourceExtent;
178→        }
179→        break;
180→      }
181→
182→      case 'align_edge': {
183→        const axis = getAnchorAxis(constraint.targetAnchor);
184→        if (!axis) break;
185→        const targetVal = getAnchorPosition(workingTarget, constraint.targetAnchor);
186→        const sourceVal = getAnchorPosition(workingSource, constraint.sourceAnchor);
187→        newPos[axis] = sourcePos[axis] + (targetVal - sourceVal) + constraint.offset;
188→        break;
189→      }
190→
191→      case 'center_axis': {
192→        const targetExt = getPartExtents(workingTarget);
193→        const sourceExt = getPartExtents(workingSource);
194→        const axisMode = constraint.axis || 'both';
195→
196→        if (axisMode === 'x' || axisMode === 'both') {
197→          newPos.x = targetPos.x + (targetExt.width - sourceExt.width) / 2;
198→        }
199→        if (axisMode === 'y' || axisMode === 'both') {
200→          newPos.y = targetPos.y + (targetExt.depth - sourceExt.depth) / 2;
201→        }
202→        break;
203→      }
204→
205→      case 'inset_edge': {
206→        const axis = getAnchorAxis(constraint.targetAnchor);
207→        if (!axis) break;
208→        const targetExt = getPartExtents(workingTarget);
209→        const sourceExt = getPartExtents(workingSource);
210→        const inset = constraint.offset || 0;
211→
212→        if (constraint.targetAnchor === 'right' || constraint.targetAnchor === 'top' || constraint.targetAnchor === 'back') {
213→          const axisSize = axis === 'x' ? targetExt.width : axis === 'y' ? targetExt.depth : targetExt.height;
214→          const sourceSize = axis === 'x' ? sourceExt.width : axis === 'y' ? sourceExt.depth : sourceExt.height;
215→          newPos[axis] = targetPos[axis] + axisSize - sourceSize - inset;
216→        } else {
217→          newPos[axis] = targetPos[axis] + inset;
218→        }
219→        break;
220→      }
221→    }
222→
223→    positions.set(source.id, newPos);
224→  }
225→
226→  return positions;
227→}
