 3→function createPartBase(type, overrides = {}) {
 4→  return {
 5→    id: generateId('part'),
 6→    type,
 7→    name: overrides.name || type,
 8→    assemblyId: overrides.assemblyId || null,
 9→    objectId: overrides.objectId || null,
10→    parentId: overrides.parentId || null,
11→    role: overrides.role || null,
12→    generatedRole: overrides.generatedRole || null,
13→    source: overrides.source || 'manual',
14→    locked: overrides.locked ?? false,
15→    sortIndex: overrides.sortIndex ?? 0,
16→    position: { x: 0, y: 0, z: 0, ...overrides.position },
17→    rotation: { x: 0, y: 0, z: 0, ...overrides.rotation },
18→    fill: overrides.fill ?? 'rgba(184, 134, 11, 0.06)',
19→    stroke: overrides.stroke ?? '#1E2433',
20→    strokeWidth: overrides.strokeWidth ?? 2,
21→    ...overrides,
22→  };
23→}
