 1→import { generateId } from '@/domain/ids';
 2→
 3→export function createAssembly(name = 'Untitled Assembly', overrides = {}) {
 4→  return {
 5→    id: generateId('asm'),
 6→    name,
 7→    description: overrides.description || '',
 8→    category: overrides.category || 'general',
 9→    partIds: overrides.partIds || [],
10→    objectId: overrides.objectId || null,
11→    parentAssemblyId: overrides.parentAssemblyId || null,
12→    childAssemblyIds: overrides.childAssemblyIds || [],
13→    source: overrides.source || 'manual',
14→    role: overrides.role || null,
15→    sortIndex: overrides.sortIndex ?? 0,
16→    ...overrides,
17→  };
18→}
19→
20→export function addPartToAssembly(assembly, partId) {
21→  if (assembly.partIds.includes(partId)) return assembly;
22→  return { ...assembly, partIds: [...assembly.partIds, partId] };
23→}
24→
25→export function removePartFromAssembly(assembly, partId) {
26→  return { ...assembly, partIds: assembly.partIds.filter((id) => id !== partId) };
27→}
28→
29→export function createTemplateAssembly(templateType, params, name) {
30→  return createAssembly(name, {
31→    category: templateType,
32→    templateType,
33→    templateParams: { ...params },
34→  });
35→}
