137→export function migrateLegacyTemplateAssemblies(project) {
138→  const objects = [...(project.objects || [])];
139→  const assemblies = [...(project.assemblies || [])];
140→  const parts = [...(project.parts || [])];
141→  const existingObjectIds = new Set(objects.map((object) => object.id));
142→
143→  for (let index = 0; index < assemblies.length; index += 1) {
144→    const assembly = assemblies[index];
145→    if (!assembly.templateType || !assembly.templateParams || assembly.objectId) continue;
146→
147→    const object = createSketchObject(assembly.name || 'Generated Object', {
148→      category: assembly.category || assembly.templateType,
149→      templateType: assembly.templateType,
150→      templateParams: { ...assembly.templateParams },
151→      dimensions: {
152→        width: assembly.templateParams.width,
153→        depth: assembly.templateParams.depth,
154→        height: assembly.templateParams.height,
155→      },
156→      source: 'generated',
157→      editingPolicy: 'parametric',
158→      assemblyIds: [assembly.id],
159→      partIds: [...(assembly.partIds || [])],
160→      summary: `Migrated ${assembly.templateType} object`,
161→      defaultName: assembly.name || 'Generated Object',
162→    });
163→
164→    if (existingObjectIds.has(object.id)) continue;
165→
166→    objects.push(object);
167→    existingObjectIds.add(object.id);
168→    assemblies[index] = {
169→      ...assembly,
170→      objectId: object.id,
171→      source: 'generated',
172→      role: assembly.role || 'legacy_root',
173→    };
174→
175→    for (let partIndex = 0; partIndex < parts.length; partIndex += 1) {
176→      const part = parts[partIndex];
177→      if (part.assemblyId !== assembly.id) continue;
178→      parts[partIndex] = {
179→        ...part,
180→        objectId: object.id,
181→        source: part.source || 'generated',
182→        locked: part.locked ?? true,
183→      };
184→    }
185→  }
186→
187→  return { ...project, objects, assemblies, parts };
188→}
189→
190→export function normalizeSketchObjects(project) {
191→  const migrated = migrateLegacyTemplateAssemblies(project);
192→  const objects = (migrated.objects || []).map(normalizeSketchObject);
193→  const assemblyObjectMap = new Map();
194→
195→  for (const object of objects) {
196→    for (const assemblyId of object.assemblyIds || []) {
197→      assemblyObjectMap.set(assemblyId, object.id);
198→    }
199→  }
200→
201→  const assemblies = (migrated.assemblies || []).map((assembly) => ({
202→    ...assembly,
203→    objectId: assembly.objectId || assemblyObjectMap.get(assembly.id) || null,
204→    source: assembly.source || ((assembly.objectId || assemblyObjectMap.get(assembly.id)) ? 'generated' : 'manual'),
205→    childAssemblyIds: [...(assembly.childAssemblyIds || [])],
206→    parentAssemblyId: assembly.parentAssemblyId || null,
207→  }));
208→
209→  const assemblyById = new Map(assemblies.map((assembly) => [assembly.id, assembly]));
210→  const parts = (migrated.parts || []).map((part) => {
211→    const assembly = part.assemblyId ? assemblyById.get(part.assemblyId) : null;
212→    const objectId = part.objectId || assembly?.objectId || null;
213→    return {
214→      ...part,
215→      objectId,
216→      source: part.source || (objectId ? 'generated' : 'manual'),
217→      locked: part.locked ?? !!objectId,
218→      role: part.role || part.generatedRole || null,
219→    };
220→  });
221→
222→  const normalizedObjects = objects.map((object) => {
223→    const assemblyIds = assemblies
224→      .filter((assembly) => assembly.objectId === object.id)
225→      .map((assembly) => assembly.id);
226→    const partIds = parts
227→      .filter((part) => part.objectId === object.id)
228→      .map((part) => part.id);
229→
230→    return normalizeSketchObject({
231→      ...object,
232→      assemblyIds,
233→      partIds,
234→    });
235→  });
236→
237→  return {
238→    ...migrated,
239→    objects: normalizedObjects,
240→    assemblies,
241→    parts,
242→  };
243→}
244→
245→export function getObjectForEntity(project, entity) {
246→  if (!entity) return null;
247→  if (entity.objectId) {
248→    return (project.objects || []).find((object) => object.id === entity.objectId) || null;
249→  }
250→  return null;
251→}
252→
253→export function buildLegacyObjectTreeFromAssembly(project, assembly) {
254→  return {
255→    kind: 'object',
256→    id: assembly.objectId,
257→    objectId: assembly.objectId,
258→    name: assembly.name,
259→    role: assembly.templateType || assembly.category || 'object',
260→    children: [buildLegacyRootAssemblyNode(project, assembly)],
261→  };
262→}
