 9→const PART_FACTORIES = {
10→  panel: createPanel,
11→  leg: createLeg,
12→  frame: createFrame,
13→  cutout: createCutout,
14→  hole: createHole,
15→};
16→
17→export function materializePartDefinition(partDefinition, overrides = {}) {
18→  const factory = PART_FACTORIES[partDefinition.type];
19→  if (!factory) {
20→    throw new Error(`Unsupported part type: ${partDefinition.type}`);
21→  }
22→
23→  return factory({
24→    name: partDefinition.name,
25→    role: partDefinition.role,
26→    ...partDefinition.props,
27→    ...overrides,
28→  });
29→}
30→
31→export function materializeTemplateDefinition(definition, overrides = {}) {
32→  const parts = [];
33→
34→  for (const assembly of definition.assemblies || []) {
35→    for (const partDefinition of assembly.parts || []) {
36→      parts.push(materializePartDefinition(partDefinition, overrides));
37→    }
38→  }
39→
40→  return {
41→    name: definition.name,
42→    parts,
43→  };
44→}
