  3→const cabinetTemplate = {
  4→  type: 'cabinet',
  5→  label: 'Cabinet',
  6→  description: 'Box with sides, shelves, optional doors and back',
  7→  parameters: [
  8→    { key: 'width', label: 'Width', type: 'number', default: 600, min: 200, max: 3000, step: 10, suffix: 'mm' },
  9→    { key: 'depth', label: 'Depth', type: 'number', default: 400, min: 150, max: 1500, step: 10, suffix: 'mm' },
 10→    { key: 'height', label: 'Height', type: 'number', default: 800, min: 200, max: 3000, step: 10, suffix: 'mm' },
 11→    { key: 'panelThickness', label: 'Panel Thickness', type: 'number', default: 18, min: 6, max: 50, step: 1, suffix: 'mm' },
 12→    { key: 'shelfCount', label: 'Shelves', type: 'integer', default: 2, min: 0, max: 10, step: 1, suffix: '' },
 13→    { key: 'doorCount', label: 'Door Count', type: 'integer', default: 2, min: 0, max: 4, step: 1, suffix: '' },
 14→    { key: 'toeKick', label: 'Toe Kick', type: 'number', default: 75, min: 0, max: 200, step: 5, suffix: 'mm' },
 15→    { key: 'hasBack', label: 'Back Panel', type: 'boolean', default: true },
 16→    { key: 'backPanelThickness', label: 'Back Thickness', type: 'number', default: 6, min: 3, max: 25, step: 1, suffix: 'mm' },
 17→  ],
 18→  buildDefinition(params) {
 19→    const { width, depth, height, panelThickness, shelfCount, doorCount, toeKick, hasBack, backPanelThickness } = params;
 20→    const innerWidth = width - 2 * panelThickness;
 21→    const innerHeight = height - panelThickness - Math.max(toeKick, panelThickness);
 22→    const bottomZ = Math.max(toeKick, panelThickness);
 23→    const caseParts = [
 24→      {
 25→        type: 'panel',
 26→        role: 'left_side',
 27→        name: 'Left Side',
 28→        props: {
 29→          width: panelThickness,
 30→          depth,
 31→          thickness: height,
 32→          material: 'plywood',
 33→          position: { x: 0, y: 0, z: 0 },
 34→        },
 35→      },
 36→      {
 37→        type: 'panel',
 38→        role: 'right_side',
 39→        name: 'Right Side',
 40→        props: {
 41→          width: panelThickness,
 42→          depth,
 43→          thickness: height,
 44→          material: 'plywood',
 45→          position: { x: width - panelThickness, y: 0, z: 0 },
 46→        },
 47→      },
 48→      {
 49→        type: 'panel',
 50→        role: 'bottom',
 51→        name: 'Bottom',
 52→        props: {
 53→          width: innerWidth,
 54→          depth,
 55→          thickness: panelThickness,
 56→          material: 'plywood',
 57→          position: { x: panelThickness, y: 0, z: bottomZ },
 58→        },
 59→      },
 60→      {
 61→        type: 'panel',
 62→        role: 'top',
 63→        name: 'Top',
 64→        props: {
 65→          width: innerWidth,
 66→          depth,
 67→          thickness: panelThickness,
 68→          material: 'plywood',
 69→          position: { x: panelThickness, y: 0, z: height - panelThickness },
 70→        },
 71→      },
 72→    ];
 73→
 74→    const shelfParts = [];
 75→    if (shelfCount > 0) {
 76→      const spacing = innerHeight / (shelfCount + 1);
 77→      for (let i = 1; i <= shelfCount; i += 1) {
 78→        const z = bottomZ + panelThickness + spacing * i - panelThickness / 2;
 79→        shelfParts.push({
 80→          type: 'panel',
 81→          role: `shelf_${i}`,
 82→          name: `Shelf ${i}`,
 83→          props: {
 84→            width: innerWidth,
 85→            depth,
 86→            thickness: panelThickness,
 87→            material: 'plywood',
 88→            position: { x: panelThickness, y: 0, z },
 89→          },
 90→        });
 91→      }
 92→    }
 93→
 94→    const doorParts = [];
 95→    if (doorCount > 0) {
 96→      const doorWidth = innerWidth / doorCount;
 97→      const doorNames = ['Left Door', 'Right Door', 'Door 3', 'Door 4'];
 98→      const doorRoles = ['left_door', 'right_door', 'door_3', 'door_4'];
 99→      for (let i = 0; i < doorCount; i += 1) {
100→        doorParts.push({
101→          type: 'panel',
102→          role: doorRoles[i],
103→          name: doorCount === 1 ? 'Door' : doorNames[i],
104→          props: {
105→            width: doorWidth,
106→            depth: panelThickness,
107→            thickness: innerHeight,
108→            material: 'plywood',
109→            position: { x: panelThickness + i * doorWidth, y: 0, z: bottomZ + panelThickness },
110→            fill: 'rgba(184, 134, 11, 0.1)',
111→          },
112→        });
113→      }
114→    }
115→
116→    const bpThick = hasBack ? backPanelThickness : 0;
117→    const backParts = hasBack ? [
118→      {
119→        type: 'panel',
120→        role: 'back',
121→        name: 'Back',
122→        props: {
123→          width,
124→          depth: bpThick,
125→          thickness: height,
126→          material: 'plywood',
127→          position: { x: 0, y: depth - bpThick, z: 0 },
128→          fill: 'rgba(120, 120, 120, 0.06)',
129→        },
130→      },
131→    ] : [];
132→
133→    return {
134→      name: `Cabinet ${width}×${depth}×${height}`,
135→      summary: 'Casework cabinet with configurable shelves and enclosure options',
136→      description: 'Side panels, horizontal case parts, optional shelves, doors, and back panel.',
137→      dimensions: { width, depth, height },
138→      assemblies: [
139→        { key: 'case', name: 'Case', sortIndex: 0, parts: caseParts },
140→        { key: 'shelves', name: 'Shelves', sortIndex: 1, parts: shelfParts },
141→        { key: 'front', name: 'Front', sortIndex: 2, parts: doorParts },
142→        { key: 'back', name: 'Back', sortIndex: 3, parts: backParts },
143→      ],
144→    };
145→  },
146→  generate(params) {
147→    return materializeTemplateDefinition(this.buildDefinition(params));
148→  },
149→};
150→
151→export default cabinetTemplate;
